   421→export const capitalize = (string) => {
   422→  if (isNullOrUndefined(string)) {
   423→    return '';
   424→  }
   425→  if (!string) return '';
   426→  const words = string?.split(' ');
   427→  let capitalizedText = '';
   428→  words.forEach((word) => {
   429→    capitalizedText += `${word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()} `;
   430→  });
   431→  return capitalizedText;
   432→};
