   452→export const formatDate = (date) => {
   453→  const year = date.getFullYear();
   454→  const month = date.getMonth();
   455→  const day = date.getDate();
   456→
   457→  const hours = date.getHours();
   458→  const minutes = date.getMinutes();
   459→  const seconds = date.getSeconds();
   460→
   461→  const halfDate = `${year}-${month + 1 > 9 ? '' : '0'}${month + 1}-${day > 9 ? '' : '0'}${day}T`;
   462→
   463→  return `${halfDate}${hours > 9 ? '' : '0'}${hours}:${minutes > 9 ? '' : '0'}${minutes}:${seconds > 9 ? '' : '0'
   464→    }${seconds}-00:00`;
   465→};
