   485→  const colorYellow = presets.colorYellowVehicle;
   486→  if (statusLowerCase === 'bloqueado' || statusLowerCase === 'em cancelamento') {
   487→    return colorRed;
   488→  }
   489→  if (statusLowerCase === 'cancelado') {
   490→    return colorRed;
   491→  }
   492→  if (statusLowerCase === 'ativo') {
   493→    return colorGreen;
   494→  }
   495→  if (statusLowerCase === 'vendido') {
   496→    return colorYellow;
   497→  }
