   658→  const actives = vehicles.filter((vehicle) => {
   659→    const statusLowerCase = String(vehicle?.plan?.status).toLowerCase();
   660→    const statusVehicle = String(vehicle.status).toLowerCase();
   661→
   662→    return (
   663→      ((statusLowerCase === 'ativo' ||
   664→        statusLowerCase === 'em pausa' ||
   665→        statusLowerCase === 'em cancelamento') &&
   666→        statusVehicle === 'desativado') ||
   667→      statusVehicle === 'ativo' ||
   668→      statusVehicle === 'vendido' ||
   669→      (statusVehicle === 'bloqueado' && statusLowerCase === 'ativo') ||
   670→      (statusVehicle === 'bloqueado' && statusLowerCase === 'em pausa')
   671→    );
   672→  });
   673→
   674→  const others = vehicles.filter((vehicle) => {
   675→    const statusLowerCase = String(vehicle?.plan?.status).toLowerCase();
   676→    const statusVehicle = String(vehicle.status).toLowerCase();
   677→    return (
   678→      (statusLowerCase !== 'em pausa' &&
   679→        statusLowerCase !== 'ativo' &&
   680→        statusVehicle !== 'ativo' &&
   681→        statusVehicle !== 'vendido') ||
   682→      (statusLowerCase === 'ativo' && statusVehicle === 'cancelado')
   683→    );
   684→  });
   685→  return {
   686→    actives,
   687→    others,
   688→    vehicles,
   689→  };
   690→};
