   760→export const addUpToCardTrio = (array, start, end) => {
   761→  let total = 0;
   762→
   763→  array.forEach((element) => {
   764→    if (
   765→      element.label === 'RECARGA' &&
   766→      moment(element.at).toDate() >= moment(start).toDate() &&
   767→      moment(element.at).toDate() <= moment(end).toDate()
   768→    ) {
   769→      total += parseFloat(element.value);
   770→    }
   771→  });
   772→
   773→  return total.toFixed(2).toString().replace('-', '');
   774→};
