   895→export const formatDateToPtBr = (dateStr = '') => {
   896→  if (dateStr?.indexOf('T') > -1) {
   897→    const splittedStr = dateStr.split('T');
   898→    const dateArray = splittedStr[0].split('-');
   899→    return dateArray[2] + '/' + dateArray[1] + '/' + dateArray[0];
   900→  } else {
   901→    return dateStr;
   902→  }
   903→};
