   905→export const zipCodeMask = (zipCode = '') => {
   906→  if (zipCode?.indexOf('-') == -1) {
   907→    return zipCode?.substring(0, 5) + '-' + zipCode?.substring(5, 9);
   908→  } else {
   909→    return zipCode;
   910→  }
   911→};
