   913→export const cpfMask = (cpf) => {
   914→  return cpf.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/g, '$1.$2.$3-$4');
   915→};
   916→
   917→export const telphoneMask = (cellPhone) => {
   918→  return cellPhone?.length === 11
   919→    ? cellPhone.replace(/^(\d\d)(\d{5})(\d{4}).*/, '($1) $2-$3')
   920→    : cellPhone.replace(/^(\d\d)(\d{4})(\d{4}).*/, '($1) $2-$3');
   921→};
