  1327→  let hasInvoiceOverdue: InvoiceFintechActive | undefined;
  1328→  let hasInvoiceClosed: InvoiceFintechActive | undefined;
  1329→  let hasInvoiceOpen: InvoiceFintechActive | undefined;
  1330→  const copyInvoices = [...invoices];
  1331→  copyInvoices.map((invoice, index) => {
  1332→    if (invoice.Pagamento === 'Não Pago') {
  1333→      if (!hasInvoiceOverdue && isInvoiceOverdue(invoice.Vencimento)) {
  1334→        hasInvoiceOverdue = { index, data: invoice, type: 'overdue' };
  1335→      } else if (!hasInvoiceClosed && isInvoiceClosed(invoice.Fechamento, invoice.Vencimento)) {
