};

/**
 *
 * @returns {{
 *  nrc: string
 *  identify_user: number
 * }}
 */
const getUserForEvent = () => {
  const {
    customerReducer: { id },
    sessionReducer: { isLogged },
  } = Store.getState();
  return {
    nrc: id,
    identify_user: isLogged ? 1 : 0,
  };
};

/**
 *
 * @param {string} screen_name
 * @param {string} screen_bussines
 * @param {string} screen_class
 * @param {{
 *  location_1: string
 *  location_2: string
 *  location_3: string
 * }} screen_info
 */
export const eventScreenViewV3 = async (
  screen_name,
  screen_class,
  screen_bussines,
  screen_info,
) => {
  if (screen_name && screen_class && screen_bussines && screen_info) {
    Dynatrace.enterManualAction(screen_name);
    Dynatrace.sendBizEvent("screen_view", {
      screen_name,
      screen_class,
      screen_bussines,
      ...screen_info,
      ...getUserForEvent(),
      environment_type: environment?.type,
    });
    // RNUxcam.tagScreenName(`${screen_info?.location_2} - ${screen_info?.location_3}`); Temporarily disabled

    await logEvent({
      screen_name: screen_name,
      screen_class: screen_class,
      screen_bussines: screen_bussines,
      ...screen_info,
      ...getUserForEvent(),
      environment_type: environment?.type,
    });
    // RNUxcam.logEvent(screen_name); Temporarily disabled
    MarketingCloudSdk.track({
      category: EventCategory.ENGAGEMENT,
      name: 'screen_view',
      attributes: {
        screen_name,
        screen_class,
        screen_bussines,
        ...screen_info,
        ...getUserForEvent(),
        environment_type: environment?.type,
      },
    });
    await analytics().logScreenView({
      screen_name: screen_name,
      screen_class: screen_class,
      screen_bussines: screen_bussines,
      ...screen_info,
      ...getUserForEvent(),
      environment_type: environment?.type,
    });
  }
};

/**
 * @deprecated
