/**
 *
 * @param {string} id
 * @param {string} properties string by Array Properties
 */
export const setUserAnalytics = async (id, properties) => {
  if (!id || !properties) {
    return;
  }
  const fontScale = (await getFontScale()).toString();
  const { personalization } = homeService;
  const isEnabledNewHome = homeService.isEnabledNewHome || Store.getState()?.featuresReducer?.forceNewHome;

  try {
    await eventPreSaveUserProperties({ logged: true, nrc: id });

    if (isEnabledNewHome) {
      await analytics().setUserProperty('segment_type', `seg_${personalization.segmentation}`);
    } else {
      await analytics().setUserProperty('segment_type', 'legado');
    }

    for (const [propertyName, propertyValue] of Object.entries(properties)) {
      await analytics().setUserProperty(propertyName, String(propertyValue));
    }

    MarketingCloudSdk.setAttribute('NRC', id);
    MarketingCloudSdk.setContactKey(id);

    Dynatrace.identifyUser(id);

    RNUxcam.setUserIdentity(id);
    RNUxcam.setUserProperty("Font scaling", fontScale);

    appsFlyer.setCustomerUserId(id);
  } catch (error) { }
};

/**
 *
 * @param {{
 *   logged: boolean
 *   nrc?: string
 * }}
 */
export const eventPreSaveUserProperties = async ({ logged, nrc }) => {
  logged = logged ? 'true' : 'false';

  if (!!nrc) {
    await analytics().setUserId(nrc);
    await analytics().setUserProperty('user_nrc', nrc);
    await analytics().setUserProperty('nrc', nrc);
  }

  await analytics().setUserProperty('identify_user', logged);
}

export const eventFb = async (eventName) => {
