      [AppEventsLogger.AppEventParams.Currency]: 'BRL',
    });
  }
};

export const setCampagin = async (details) => {
  if (!details) return;
  await analytics().logCampaignDetails({
    source: details.source,
    medium: details.medium,
    campaign: details.campaign,
    content: details.content,
  });
};

export function responsiveSize(size) {
  return size * (Layout.isSmallDevice ? 0.8 : 1);
}

export const capitalize = (string) => {
  if (isNullOrUndefined(string)) {
    return '';
  }
  if (!string) return '';
  const words = string?.split(' ');
  let capitalizedText = '';
  words.forEach((word) => {
    capitalizedText += `${word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()} `;
  });
  return capitalizedText;
};

export function transformSequenceToUppercase(string) {
  return string.replace(/\b[iI]+\b/g, (match) => match.toUpperCase());
}

export const getVehicleIdentifier = (vehicle) => {
  if (vehicle.identificadorVeiculo !== null) {
    if (vehicle.listaPontoAcessoAtivo.length > 0) {
      return vehicle.listaPontoAcessoAtivo[0].numeroIdentificador;
    }
    return vehicle.listaPontoAcessoInativo[0].numeroIdentificador;
  }
  return '';
};

export const isNullOrUndefined = (object) => {
  return object === null || object === undefined;
};

export const formatDate = (date) => {
  const year = date.getFullYear();
  const month = date.getMonth();
  const day = date.getDate();

  const hours = date.getHours();
  const minutes = date.getMinutes();
  const seconds = date.getSeconds();

  const halfDate = `${year}-${month + 1 > 9 ? '' : '0'}${month + 1}-${day > 9 ? '' : '0'}${day}T`;

  return `${halfDate}${hours > 9 ? '' : '0'}${hours}:${minutes > 9 ? '' : '0'}${minutes}:${seconds > 9 ? '' : '0'
    }${seconds}-00:00`;
};

export const dateToStr = (date) => {
  const year = date.getFullYear();
  const month = date.getMonth();
  const day = date.getDate();
  return `${day > 9 ? '' : '0'}${day}/${month + 1 > 9 ? '' : '0'}${month + 1}/${year}`;
};

export const dateWithoutYearToStr = (date) => {
  date = new Date(date);
  const month = date.getUTCMonth();
  const day = date.getUTCDate();
  return `${day > 9 ? '' : '0'}${day}/${month + 1 > 9 ? '' : '0'}${month + 1}`;
};

export const _colorStatusVehicle = (status, presets, type) => {
  const statusLowerCase = String(status).toLowerCase().trim();
  const colorRed = presets.colorRedVehicle;
  const colorGreen = presets.colorGreenVehicle;
  const colorYellow = presets.colorYellowVehicle;
  if (statusLowerCase === 'bloqueado' || statusLowerCase === 'em cancelamento') {
    return colorRed;
  }
  if (statusLowerCase === 'cancelado') {
    return colorRed;
  }
  if (statusLowerCase === 'ativo') {
    return colorGreen;
  }
  if (statusLowerCase === 'vendido') {
    return colorYellow;
  }
  if (statusLowerCase === 'confirmar recebimento') {
    return colorYellow;
  }
  if (statusLowerCase === 'retirar na loja') {
    return colorYellow;
  }
  if (statusLowerCase === 'em análise') {
    return colorYellow;
  }
  if (statusLowerCase === 'desativado') {
    return colorRed;
  }
  if (
    statusLowerCase === 'não aprovado' ||
    statusLowerCase === 'reprovado' ||
    statusLowerCase === 'em pausa' ||
    statusLowerCase === 'pausado'
  ) {
    return colorRed;
  }
  if (type === 2) {
    return colorRed;
  }
  return colorYellow;
};

export const _isPausedPlanTime = (status) => {
  const statusLowerCase = String(status).toLowerCase();
  if (statusLowerCase === 'em pausa') {
    return true;
  }
  return false;
};

export const _colorStatusPlanTime = (status, presets) => {
  const colorRed = presets.colorRedVehicle;
  const colorGreen = presets.colorGreenVehicle;
  if (_isPausedPlanTime(status)) {
    return colorRed;
  }
  if (String(status).toLowerCase() !== 'ativo') {
    return colorRed;
  }
