export const _filterVehicles = (vehicles) => {
  const actives = vehicles.filter((vehicle) => {
    const statusLowerCase = String(vehicle?.plan?.status).toLowerCase();
    const statusVehicle = String(vehicle.status).toLowerCase();

    return (
      ((statusLowerCase === 'ativo' ||
        statusLowerCase === 'em pausa' ||
        statusLowerCase === 'em cancelamento') &&
        statusVehicle === 'desativado') ||
      statusVehicle === 'ativo' ||
      statusVehicle === 'vendido' ||
      (statusVehicle === 'bloqueado' && statusLowerCase === 'ativo') ||
      (statusVehicle === 'bloqueado' && statusLowerCase === 'em pausa')
    );
  });

  const others = vehicles.filter((vehicle) => {
    const statusLowerCase = String(vehicle?.plan?.status).toLowerCase();
    const statusVehicle = String(vehicle.status).toLowerCase();
    return (
      (statusLowerCase !== 'em pausa' &&
        statusLowerCase !== 'ativo' &&
        statusVehicle !== 'ativo' &&
        statusVehicle !== 'vendido') ||
      (statusLowerCase === 'ativo' && statusVehicle === 'cancelado')
    );
  });
  return {
    actives,
    others,
    vehicles,
  };
};

