export const getSupplyArray = (array) => {
  const arraySupply = [];
  for (let index = 0; index < array.length; index++) {
    const element = array[index];
    const nextElement = array[index + 1];
    if (element.label === 'ABASTECE') {
      if (
        nextElement !== undefined &&
        nextElement.label === 'RECARGA' &&
        -element.value === nextElement.value
      ) {
        arraySupply.push(nextElement);
      }
      arraySupply.push(element);
    }
  }
  return arraySupply;
};

export const getOtherExpensesArray = (array) => {
  const arrayOtherExpenses = [];
  for (let index = 0; index < array.length; index++) {
    const element = array[index];
    const backElement = array[index - 1];
    if (element.label !== 'ABASTECE') {
      if (
        !(
          element.label === 'RECARGA' &&
          backElement !== undefined &&
          backElement.label === 'ABASTECE' &&
          -element.value === backElement.value
        )
      ) {
        arrayOtherExpenses.push(element);
      }
    }
  }
  return arrayOtherExpenses;
};

export const addUpToCardTrio = (array, start, end) => {
  let total = 0;

  array.forEach((element) => {
    if (
      element.label === 'RECARGA' &&
      moment(element.at).toDate() >= moment(start).toDate() &&
      moment(element.at).toDate() <= moment(end).toDate()
    ) {
      total += parseFloat(element.value);
    }
  });

  return total.toFixed(2).toString().replace('-', '');
};

