export const getMessageInfoCardTrio = (value, monthName, isLast, isFuel) => {
  if (value === parseFloat('0').toFixed(2)) {
    if (isLast) {
      // Mês anterior
      return isFuel
        ? // Mensagem abastecimento
        `Você não teve nenhum lançamento no seu cartão em ${monthName}.`
        : // Mensagem outros gastos
        `Você não teve nenhum lançamento referente a pedágios, estacionamentos, drive-thrus, mensalidade e outros no seu cartão em${monthName}`;
    }
    // Mês atual
    return isFuel
      ? // Mensagem abastecimento
      `Você ainda não teve nenhum lançamento no seu cartão em ${monthName}.`
      : // Mensagem outros gastos
      `Você ainda não teve nenhum lançamento no seu cartão em ${monthName}.\n\n` +
      `ATENÇÃO!\n` +
      `Só lançaremos no seu cartão os gastos com estacionamento, pedágio, drive-thru e outros quando a soma for igual ou maior que R$20,00.`;
  }
  if (value > parseFloat('0').toFixed(2)) {
    if (isLast) {
      // Mês anterior
      return isFuel
        ? // Mensagem abastecimento
        `O valor de ${formatForReal(value)} já foi lançado no seu cartão em ${monthName}.`
        : // Mensagem outros gastos
        `O valor de ${formatForReal(
          value
        )} referente a pedágios, estacionamentos, drive-thrus, mensalidade e outros, já foi lançado no seu cartão em ${monthName}.`;
    }
    // Mês atual
    return isFuel
      ? // Mensagem abastecimento
      `O valor de ${formatForReal(
        value
      )} já foi lançado no seu cartão em ${monthName} e pode sofrer alterações até o final do mês.`
      : // Mensagem outros gastos
      `O valor de ${formatForReal(
        value
      )} já foi lançado no seu cartão em ${monthName} e pode sofrer alterações até o final do mês.\n\n` +
      `ATENÇÃO!\n\n` +
      `Só lançaremos no seu cartão os gastos com estacionamento, pedágio, drive-thru e outros quando a soma for igual ou maior que R$20,00.`;
  }
};

