export const textingInsurance = (
  sendTo,
  name = '',
  cpf = '',
  birthDate = '',
  zipCode = '',
  telphone = '',
  email = '',
  additionalText = ''
) => {
  const defaultText = `Olá, estou interessado em saber mais sobre o Seguro Sem Parar`;
  const nameText = `\nNome completo: ${capitalizeAndToLower(name, true)}`;
  const cpfText = `\nCpf: ${cpfMask(cpf)}`;
  const birthDateText = `\nData de nascimento: ${formatDateToPtBr(birthDate)}`;
  const emailText = `\nE-mail: ${email.toLowerCase()}`;
  const telphoneText = `\nTelefone: ${telphoneMask(telphone)}`;
  const zipCodeText = `\nCEP: ${zipCodeMask(zipCode)}`;
  let text = defaultText;
  text += name ? nameText : '';
  text += cpf ? cpfText : '';
  text += birthDate ? birthDateText : '';
  text += email ? emailText : '';
  text += telphone ? telphoneText : '';
  text += zipCode ? zipCodeText : '';
  text += additionalText ? additionalText : '';
  Linking.openURL(`whatsapp://send?text=${text}&phone=${sendTo}`);
};

export const formatDateToPtBr = (dateStr = '') => {
  if (dateStr?.indexOf('T') > -1) {
    const splittedStr = dateStr.split('T');
    const dateArray = splittedStr[0].split('-');
    return dateArray[2] + '/' + dateArray[1] + '/' + dateArray[0];
  } else {
    return dateStr;
  }
};

export const zipCodeMask = (zipCode = '') => {
  if (zipCode?.indexOf('-') == -1) {
    return zipCode?.substring(0, 5) + '-' + zipCode?.substring(5, 9);
  } else {
    return zipCode;
  }
};

export const cpfMask = (cpf) => {
  return cpf.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/g, '$1.$2.$3-$4');
};

export const telphoneMask = (cellPhone) => {
  return cellPhone?.length === 11
    ? cellPhone.replace(/^(\d\d)(\d{5})(\d{4}).*/, '($1) $2-$3')
    : cellPhone.replace(/^(\d\d)(\d{4})(\d{4}).*/, '($1) $2-$3');
};

export const CheckRules = async (rules, facts) => {
  const engine = new Engine();
  for (let index = 0; index < rules.length; index++) {
    engine.addRule(rules[index]);
  }
  const { events } = await engine.run(facts);
  const failures = events.map((event) => event?.params);
  return failures;
};

