export const updateVehiclesLead = (lead, plate, brand, age, model) => {
  const findVehicle = lead?.veiculos?.find((data) => data?.placa == plate);
  if (findVehicle) {
    lead.veiculos = lead?.veiculos?.map((data) => {
      if (data?.placa == plate) {
        return {
          marca: brand,
          ano: age?.toString(),
          modelo: model,
          placa: plate,
          temSeguro: false,
          vigencia: '',
          seguradora: '',
        };
      } else {
        return {
          ...data,
          temSeguro: false,
          vigencia: '',
          seguradora: '',
        };
      }
    });
  } else {
    if (lead?.veiculos?.length > 0) {
      lead?.veiculos?.push({
        marca: brand,
        ano: age?.toString(),
        modelo: model,
        placa: plate,
        temSeguro: false,
        vigencia: '',
        seguradora: '',
      });
    } else {
      lead.veiculos = [
        {
          marca: brand,
          ano: age?.toString(),
          modelo: model,
          placa: plate,
          temSeguro: false,
          vigencia: '',
          seguradora: '',
        },
      ];
    }
  }
  const leadToSend = {
    ...lead,
    veiculos: lead.veiculos,
  };
  return leadToSend;
};
