          subtitle: 'Nossa plataforma está em manutenção.\nTente novamente mais tarde. ',
          description: 'Entre em contato com a gente para mais informações.',
          connectError: true,
          goBack: 1,
          whatsAppEvent: 'seguro_indisponivel_whats',
          callEvent: 'seguro_indisponivel_telefone',
        })
      );
      break;
    default:
      break;
  }
};

export const calculateAge = (birthdate: string): number => {
  const today = new Date();
  const birthDate = new Date(Date.parse(birthdate));
  let age = today.getFullYear() - birthDate.getFullYear();
  const month = today.getMonth() - birthDate.getMonth();
  if (month < 0 || (month === 0 && today.getDate() < birthDate.getDate())) {
    age--;
  }
  return age;
};
export const getActiveInvoice = (
  invoices: InvoiceFintechItem[]
): InvoiceFintechActive | undefined => {
  let hasInvoiceOverdue: InvoiceFintechActive | undefined;
  let hasInvoiceClosed: InvoiceFintechActive | undefined;
  let hasInvoiceOpen: InvoiceFintechActive | undefined;
  const copyInvoices = [...invoices];
  copyInvoices.map((invoice, index) => {
    if (invoice.Pagamento === 'Não Pago') {
      if (!hasInvoiceOverdue && isInvoiceOverdue(invoice.Vencimento)) {
        hasInvoiceOverdue = { index, data: invoice, type: 'overdue' };
      } else if (!hasInvoiceClosed && isInvoiceClosed(invoice.Fechamento, invoice.Vencimento)) {
        hasInvoiceClosed = { index, data: invoice, type: 'closed' };
      } else if (!hasInvoiceOpen) {
        hasInvoiceOpen = { index, data: invoice, type: 'open' };
      }
    }
  });

  if (hasInvoiceOverdue) {
    return hasInvoiceOverdue;
  }

  if (hasInvoiceClosed) {
    return hasInvoiceClosed;
  }

  if (hasInvoiceOpen) {
    return hasInvoiceOpen;
  }
  return undefined;
};
export const isInvoiceOverdue = (dueDate: string): boolean => {
  const currentDate = moment();
  const formattedDueDate = moment(dueDate).add(2, 'days');
  return formattedDueDate.isBefore(currentDate);
};

export const isInvoiceClosed = (closingDate: string, dueDate: string): boolean => {
  const currentDate = moment();
  if (moment().isAfter(closingDate) && !moment(dueDate).add(2, 'days').isBefore(currentDate)) {
    return true;
  }
  return false;
};

export const idWithoutUTM = (idOffer: string) => {
  if (idOffer) {
    if (idOffer?.includes('/utm')) {
      const UTMIndex = idOffer?.indexOf('/utm');
      const urlWithoutUTM = idOffer?.slice(0, UTMIndex);
      return Number(urlWithoutUTM);
    }
  }
  return Number(idOffer);
};

export const getIdWithoutUTMAsStringToInsurance = (idOffer: string) => {
  if (idOffer) {
    if (idOffer?.includes('/?utm')) {
      const UTMIndex = idOffer?.indexOf('/?utm');
      const urlWithoutUTM = idOffer?.slice(0, UTMIndex);
      return urlWithoutUTM;
    }
  }
  return idOffer;
};

/**
 *
 * @param {{
* name?: string
* values?: object
* }} eventAppsflyer
*/
export const eventContentAppsFlyer = (eventName, eventValues = {}) => {
  if (eventName) {
    appsFlyer.logEvent(eventName, eventValues);
  }
}

/**
 *
 * @param {{
* name?: string
* values?: object
* }} eventAppsflyer
*/
export const eventContentUxCam = (eventName, eventValues = {}) => {
  if (eventName) {
    RNUxcam.logEvent(eventName, eventValues);
  }
}


export const formatCurrencyCashback = (value: number): string => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(value);
};

