   *   location_1: 'fintech',
   *   location_2: 'invoice',
   *   location_3: 'pay-button'
   * });
   * ```
   */
  export function eventSelectContent(eventInfo: EventSelectContentInfo): Promise<void>;

  /**
   * Tracks modal view events across analytics platforms
   *
   * Logs when modals or overlays are displayed to users
   *
   * @param eventInfo - Modal information including content ID and location
   * @returns Promise that resolves when all analytics calls complete
   *
   * @example
   * ```typescript
   * await eventModalView({
   *   content_id: 'terms-modal',
   *   screen_bussines: 'onboarding',
   *   location_1: 'fintech',
   *   location_2: 'cards',
   *   location_3: 'terms-conditions'
   * });
   * ```
   */
  export function eventModalView(eventInfo: EventModalViewInfo): Promise<void>;

  /**
   * Tracks screen view events with detailed context
   *
   * Logs screen navigation and view events to Firebase Analytics, Dynatrace,
   * and other analytics platforms with business context
   *
   * @param screen_name - Display name of the screen
   * @param screen_class - Technical class or identifier of the screen
   * @param screen_bussines - Business context or category
   * @param screen_info - Hierarchical location information
   * @returns Promise that resolves when all analytics calls complete
   *
   * @example
   * ```typescript
   * await eventScreenViewV3(
   *   'Invoice Details',
   *   'InvoiceDetailsScreen',
   *   'fintech',
   *   {
   *     location_1: 'fintech',
   *     location_2: 'invoice',
   *     location_3: 'details'
   *   }
   * );
   * ```
   */
  export function eventScreenViewV3(
    screen_name: string,
    screen_class: string,
    screen_bussines: string,
    screen_info: ScreenInfo
  ): Promise<void>;

  /**
   * Tracks server response events
   *
   * Logs API responses and server interactions for monitoring and analytics
   *
   * @param eventInfo - Response information including optional content and plate data
   * @returns Promise that resolves when all analytics calls complete
   *
   * @example
   * ```typescript
   * await eventServerResponse({
   *   content_type: 'api_response',
   *   event_plate: 'ABC1234',
   *   location_1: 'fintech',
   *   location_2: 'invoice',
   *   location_3: 'fetch-details'
   * });
   * ```
   */
